.darma-loader-darma-custom-759 {
  color: var(--loader-color, #8b5cf6);
height: 15px;
aspect-ratio: 4;
display: grid;
}
.darma-loader-darma-custom-759:before,
.darma-loader-darma-custom-759:after {
content: "";
grid-area: 1/1;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 25% 100%;
animation: darma-loader-darma-custom-759-l34 1s infinite;
transform: translate(var(--d,0)) rotate(0);
}
.darma-loader-darma-custom-759:after {
--d: 37.5%;
animation-delay: .5s;
}
@keyframes darma-loader-darma-custom-759-l34 {
50%,100% {transform: translate(var(--d,0)) rotate(.5turn)}
}

